  };

  // From (221,114), Forester at (216,114): -5 west → 648 - 5*50 = 398
  await click(398, 384);
  const pos = await page.evaluate(() => window.__latestGameState?.player_position);

  // Talk multiple times
  const results = [];
  for (let i = 0; i < 8; i++) {
    const talked = await page.evaluate((id) => window.__talkToNPC(id), '1-82331128');
    await page.waitForTimeout(1500);
    const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
    const s = JSON.parse(state);
