async (page) => {
  let kills = 0;
  let finalLevel = 6;

  for (let i = 0; i < 15; i++) {
    const attackResult = await page.evaluate(() => JSON.stringify(window.__attackMob('Rat')));
    const att = JSON.parse(attackResult);

    if (att.error) {
      // Move to find more rats
      await page.evaluate(({x, y}) => {
        const canvas = document.getElementById('cursor');
        canvas.dispatchEvent(new MouseEvent('mousedown', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
        canvas.dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
      }, {x: 648 + (Math.random()-0.5)*300, y: 384 + (Math.random()-0.5)*200});
      await page.waitForTimeout(2000);
      continue;
    }

    await page.waitForTimeout(12000);
    kills++;

    const s = await page.evaluate(() => JSON.parse(JSON.stringify(window.__latestGameState)));
    finalLevel = s.player_stats.level;

    // Emergency heal
    if (s.ui_state.is_dead || s.ui_state.respawn_button_visible) {
      await page.evaluate(() => document.getElementById('respawn')?.click());
      await page.waitForTimeout(2000);
      await page.evaluate(() => { window.game.menu.warp.show(); setTimeout(() => document.getElementById('warp0').click(), 300); });
      await page.waitForTimeout(3000);
      break;
    }
    if (s.player_stats.hp < s.player_stats.max_hp * 0.4) {
      // Wait for regen
      await page.waitForTimeout(5000);
    }
  }

  const final = await page.evaluate(() => JSON.parse(JSON.stringify(window.__latestGameState)));
  return JSON.stringify({
    kills,
    level: final.player_stats.level,
    hp: final.player_stats.hp + '/' + final.player_stats.max_hp,
    skills: final.skills,
    pos: final.player_position
  });
}
